<?php namespace App\Services\Auth; use App\Models\Auth\RefreshToken; use Illuminate\Support\Str; class TokenService { public function generateTokenPair($user) { $family = Str::uuid(); $accessToken = $this->generateAccessToken($user); $refreshToken = $this->generateRefreshToken($user, $family); return compact('accessToken', 'refreshToken'); } private function generateAccessToken($user) { return jwt_encode(['userId' => $user->id, 'roles' => $user->roles->pluck('slug'), 'groups' => $user->groups->pluck('slug'), 'perms' => $user->getAllPermissions()], env('JWT_SECRET'), 'HS256'); } private function generateRefreshToken($user, $family) { $token = Str::random(64); RefreshToken::create(['user_id' => $user->id, 'token_hash' => hash('sha256', $token), 'family' => $family, 'expires_at' => now()->addDays(7), 'ip_address' => request()->ip(), 'device_fingerprint' => request()->input('deviceFingerprint')]); return $token; } }
